  "inlineSchema": "// Imboni Platform - Database Schema\n// National Civic Governance Platform\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ============ ENUMS ============\n\nenum AdministrativeLevel {\n  VILLAGE // Umudugudu\n  CELL // Akagari\n  SECTOR // Umurenge\n  DISTRICT // Akarere\n  PROVINCE // Intara\n  NATIONAL // Igihugu\n}\n\nenum UserRole {\n  CITIZEN\n  LEADER\n  ADMIN\n  OVERSIGHT\n  NGO\n}\n\nenum UserStatus {\n  ACTIVE\n  SUSPENDED\n  INACTIVE\n}\n\nenum ProtectionLevel {\n  ANONYMOUS\n  PROTECTED\n  IDENTIFIED\n}\n\nenum CaseCategory {\n  JUSTICE\n  HEALTH\n  LAND\n  INFRASTRUCTURE\n  SECURITY\n  SOCIAL\n  EDUCATION\n  OTHER\n}\n\nenum CaseUrgency {\n  NORMAL\n  HIGH\n  EMERGENCY\n}\n\nenum CaseStatus {\n  OPEN\n  IN_PROGRESS\n  RESOLVED\n  ESCALATED\n  CLOSED\n}\n\nenum ActionType {\n  ACKNOWLEDGED\n  COMMENT\n  STATUS_UPDATE\n  ASSIGNMENT\n  RESOLUTION\n}\n\nenum TriggerReason {\n  TIME_EXPIRED\n  EMERGENCY_OVERRIDE\n  MANUAL_ESCALATION\n}\n\nenum NotificationChannel {\n  SMS\n  EMAIL\n  PUSH\n}\n\n// ============ MODELS ============\n\n// 2.1 Administrative Hierarchy\nmodel AdministrativeUnit {\n  id        String               @id @default(cuid())\n  name      String\n  level     AdministrativeLevel\n  code      String               @unique\n  parentId  String?              @map(\"parent_id\")\n  parent    AdministrativeUnit?  @relation(\"UnitHierarchy\", fields: [parentId], references: [id])\n  children  AdministrativeUnit[] @relation(\"UnitHierarchy\")\n  createdAt DateTime             @default(now()) @map(\"created_at\")\n\n  leaderAssignments LeaderAssignment[]\n  cases             Case[]\n  caseAssignments   CaseAssignment[]\n\n  @@map(\"administrative_units\")\n}\n\n// 2.2 Users & Roles\nmodel User {\n  id        String     @id @default(cuid())\n  role      UserRole   @default(CITIZEN)\n  phone     String?    @unique\n  email     String?    @unique\n  password  String\n  status    UserStatus @default(ACTIVE)\n  createdAt DateTime   @default(now()) @map(\"created_at\")\n\n  profile           CitizenProfile?\n  leaderAssignments LeaderAssignment[]\n  caseAssignments   CaseAssignment[]   @relation(\"AssignedLeader\")\n  caseActions       CaseAction[]\n  notifications     Notification[]\n  auditLogs         AuditLog[]\n\n  @@map(\"users\")\n}\n\n// 2.2B Leader Assignments\nmodel LeaderAssignment {\n  id                   String             @id @default(cuid())\n  userId               String             @map(\"user_id\")\n  user                 User               @relation(fields: [userId], references: [id])\n  administrativeUnitId String             @map(\"administrative_unit_id\")\n  administrativeUnit   AdministrativeUnit @relation(fields: [administrativeUnitId], references: [id])\n  positionTitle        String             @map(\"position_title\")\n  startDate            DateTime           @map(\"start_date\")\n  endDate              DateTime?          @map(\"end_date\")\n  isActive             Boolean            @default(true) @map(\"is_active\")\n\n  @@map(\"leader_assignments\")\n}\n\n// 2.3 Citizen Identity (RESTRICTED ACCESS)\nmodel CitizenProfile {\n  id              String          @id @default(cuid())\n  userId          String          @unique @map(\"user_id\")\n  user            User            @relation(fields: [userId], references: [id])\n  nationalId      String?         @unique @map(\"national_id\")\n  protectionLevel ProtectionLevel @default(ANONYMOUS) @map(\"protection_level\")\n\n  @@map(\"citizen_profiles\")\n}\n\n// 2.4 Case / Issue Management\nmodel Case {\n  id                   String              @id @default(cuid())\n  caseReference        String              @unique @map(\"case_reference\")\n  category             CaseCategory\n  urgency              CaseUrgency         @default(NORMAL)\n  title                String\n  description          String\n  administrativeUnitId String              @map(\"administrative_unit_id\")\n  administrativeUnit   AdministrativeUnit  @relation(fields: [administrativeUnitId], references: [id])\n  currentLevel         AdministrativeLevel @map(\"current_level\")\n  status               CaseStatus          @default(OPEN)\n  submittedAnonymously Boolean             @default(false) @map(\"submitted_anonymously\")\n  submitterId          String?             @map(\"submitter_id\")\n  createdAt            DateTime            @default(now()) @map(\"created_at\")\n  resolvedAt           DateTime?           @map(\"resolved_at\")\n\n  assignments      CaseAssignment[]\n  escalationEvents EscalationEvent[]\n  actions          CaseAction[]\n  notifications    Notification[]\n\n  @@index([caseReference])\n  @@index([status])\n  @@map(\"cases\")\n}\n\n// 2.5 Case Assignment\nmodel CaseAssignment {\n  id                   String             @id @default(cuid())\n  caseId               String             @map(\"case_id\")\n  case                 Case               @relation(fields: [caseId], references: [id])\n  administrativeUnitId String             @map(\"administrative_unit_id\")\n  administrativeUnit   AdministrativeUnit @relation(fields: [administrativeUnitId], references: [id])\n  leaderId             String             @map(\"leader_id\")\n  leader               User               @relation(\"AssignedLeader\", fields: [leaderId], references: [id])\n  assignedAt           DateTime           @default(now()) @map(\"assigned_at\")\n  deadlineAt           DateTime           @map(\"deadline_at\")\n  completedAt          DateTime?          @map(\"completed_at\")\n  escalationReason     String?            @map(\"escalation_reason\")\n  isActive             Boolean            @default(true) @map(\"is_active\")\n\n  @@index([caseId])\n  @@index([deadlineAt])\n  @@map(\"case_assignments\")\n}\n\n// 2.6 Escalation Events (IMMUTABLE)\nmodel EscalationEvent {\n  id            String              @id @default(cuid())\n  caseId        String              @map(\"case_id\")\n  case          Case                @relation(fields: [caseId], references: [id])\n  fromLevel     AdministrativeLevel @map(\"from_level\")\n  toLevel       AdministrativeLevel @map(\"to_level\")\n  triggeredBy   String              @default(\"SYSTEM\") @map(\"triggered_by\")\n  triggerReason TriggerReason       @map(\"trigger_reason\")\n  triggeredAt   DateTime            @default(now()) @map(\"triggered_at\")\n\n  @@index([caseId])\n  @@map(\"escalation_events\")\n}\n\n// 2.7 Case Actions\nmodel CaseAction {\n  id          String     @id @default(cuid())\n  caseId      String     @map(\"case_id\")\n  case        Case       @relation(fields: [caseId], references: [id])\n  performedBy String     @map(\"performed_by\")\n  performer   User       @relation(fields: [performedBy], references: [id])\n  actionType  ActionType @map(\"action_type\")\n  notes       String?\n  createdAt   DateTime   @default(now()) @map(\"created_at\")\n\n  @@map(\"case_actions\")\n}\n\n// 2.8 Audit Logs (APPEND-ONLY)\nmodel AuditLog {\n  id          String   @id @default(cuid())\n  entityType  String   @map(\"entity_type\")\n  entityId    String   @map(\"entity_id\")\n  action      String\n  performedBy String?  @map(\"performed_by\")\n  performer   User?    @relation(fields: [performedBy], references: [id])\n  oldValue    Json?    @map(\"old_value\")\n  newValue    Json?    @map(\"new_value\")\n  timestamp   DateTime @default(now())\n\n  @@index([entityType, entityId])\n  @@map(\"audit_logs\")\n}\n\n// 2.9 Notifications\nmodel Notification {\n  id        String              @id @default(cuid())\n  userId    String              @map(\"user_id\")\n  user      User                @relation(fields: [userId], references: [id])\n  caseId    String?             @map(\"case_id\")\n  case      Case?               @relation(fields: [caseId], references: [id])\n  channel   NotificationChannel\n  message   String\n  sentAt    DateTime?           @map(\"sent_at\")\n  createdAt DateTime            @default(now()) @map(\"created_at\")\n\n  @@map(\"notifications\")\n}\n",
